import{c as i,Q as l,j as r,g as e,n as o}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"论小洛伦佐去世后佛罗伦","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/213-论小洛伦佐去世后佛罗伦.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/213-论小洛伦佐去世后佛罗伦.md"}'),t={name:"research/machiavelli/machiavelli/diplomatic/lower/213-论小洛伦佐去世后佛罗伦.md"};function n(c,a,s,m,d,_){return l(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"论小洛伦佐去世后佛罗伦",tabindex:"-1"},[o("论小洛伦佐去世后佛罗伦 "),e("a",{class:"header-anchor",href:"#论小洛伦佐去世后佛罗伦","aria-label":'Permalink to "论小洛伦佐去世后佛罗伦"'},"​")],-1),e("p",null,"论小洛伦佐去世后佛罗伦萨的政务 立即恢复他们全部的权力，既不利于您朋友的安全，也不利于陛下您权威 的维持；所以，有必要部分地恢复，部分地许诺。通过这种方式，可以让 他们确信再度掌权。因此，我估计，您有必要重新开放“千人议事厅”或 者至少“六百公民议事厅”。正如过去那样，除了“六十五人委员会”、 “两百人会议”以及“八人巴利阿” (公安八人委员会)之外，将从这些 人中选拔所有的公职者和行政长官；在您和梅迪奇枢机主教的有生之年， 所有这些人都由你们全权任命。而且，为了在这一议事会的选举中让您的 朋友们确信，他们的名字已经被放入选举袋，陛下您应当任命八人“中枢 委员会”——他们处于秘密状态——他们可以宣布他们中意的人当选，并 且不可以拒绝任何人当选。此外，为了使公民普遍相信当选者的名字来自 选举袋，议事会应当被允许秘密地选派两位公民来监督选举。 如果不能让公民普遍满意，想要建立一个稳定的政府终究是不可能 的；而如果议事厅不重新开放，佛罗伦萨的大多数公民就不会满意。①因 此，如果有人想在佛罗伦萨建立一个共和国，就必须再度开放该议事厅， 并将选举普及至大多数公民。陛下您肯定清楚，无论谁计划采取这一政府 形式，他都会把重新开放它视为当务之急。因此，最好的办法便是，您以 安全可靠的条件和方法开放它；并杜绝任何可能成为您敌人的人有机可 乘，使之重新开放，因为，此举将招致您的愤怒，并使您的朋友陷入灭顶 之灾。 只要政府如此组织，只有陛下您和万人敬仰的枢机主教能够万寿无 疆，那么,您就没有必要再做其他任何安排。可是，您总有寿终正寝的那 一天，并且您也希望给后世留下一个完美的共和国，这个共和国的每个组 成部分都很健全，并且每个人都有目共睹。因此，为了让全体人民如愿以",-1),e("p",null,"①这里的议事厅指大议会议事厅(现在被称为五百人议事厅[Salone dei Cinquecento],位于韦奇奥宫)。 1494年民众政府建立后，恢复了人民大会和公社大会，并将二者合并为一个机构，即所谓“大议会” (Consiglio maggiore/ Consiglio grande,也译“大参议会”或“大议事会”)。任何公民，只要按规定纳 税，年满29岁，三代之内至少有一人曾有资格在三大行政机构(执政团、贤人团和旗手团)任职，便有资 格参加大议会。1512年梅迪奇家族复辟，大议会被废除，议事厅被关闭。——中译者注",-1),e("p",null,"Legazioni,commissarie,scrittidi governo",-1)])])}const f=i(t,[["render",n]]);export{h as __pageData,f as default};
